#include<cstdio>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1010,Mod=1e9+7,Inv2=5e8+4,Inv4=1ll*Inv2*Inv2%Mod;
int n,qm,m,T;std::map<int,int> dp;int a[N],p[N];
inline void ins(int x,int y){a[++m]=(1<<x)|(1<<y);p[m]=Inv2;}
inline int dfs(int S)
{
	if(S==T)return 1;if(dp.count(S))return dp[S];
	int i=0,ans=0;for(int j=0;j<n;++j)if(!(S>>j&1)){i=j;break;}
	rep(1,m,j)if((a[j]>>i&1)&&!(S&a[j]))ans=(1ll*dfs(S|a[j])*p[j]+ans)%Mod;
	return dp[S]=ans;
}
int main()
{
	n=read();qm=read();T=(1<<2*n)-1;
	int x,y,x1,y1;while(qm--)switch(read())
	{
		case 0:
		{
			x=read()-1;y=read()-1;ins(x,y+n);
			break;
		}
		case 1:
		{
			x=read()-1;y=read()-1;x1=read()-1;y1=read()-1;ins(x,y+n);ins(x1,y1+n); 
			if(x!=x1&&y!=y1)a[++m]=(1<<x)|(1<<(y+n))|(1<<x1)|(1<<(y1+n)),p[m]=Inv4;
			break;
		}
		case 2:
		{
			x=read()-1;y=read()-1;x1=read()-1;y1=read()-1;ins(x,y+n);ins(x1,y1+n); 
			if(x!=x1&&y!=y1)a[++m]=(1<<x)|(1<<(y+n))|(1<<x1)|(1<<(y1+n)),p[m]=Mod-Inv4;
			break;
		}
	}
	printf("%lld\n",(1ll<<n)*dfs(0)%Mod);
}
